module shift_register(  
    input wire clk,  
    input wire reset,  
    input wire [7:0] data_in,  
    output reg serial_out  
);  
    reg [7:0] clear_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            clear_reg <= 8'b0;  
        end else begin  
            clear_reg <= {clear_reg[6:0], data_in[0]};  
        end  
    end  

    always @(clear_reg) begin  
        serial_out <= clear_reg[0];  
    end  
endmodule
